  private void ResolveLevelAnimationStart(
    int? previousPlayerLevel,
    int? previousPlayerXp,
    int? previousPlayerMaxXp)
  {
    this._startPlayerLevel = this._targetPlayerLevel;
    this._startPlayerMaxXp = this._targetPlayerMaxXp;
    this._startPlayerXp = Math.Max(0, this._targetPlayerXp - Math.Max(8, this._targetPlayerMaxXp / 5));
