      int max = Math.Max(1, previousPlayerMaxXp.Value);
      int num2 = Math.Clamp(previousPlayerXp.Value, 0, max);
      if (num1 <= this._targetPlayerLevel)
      {
        this._startPlayerLevel = num1;
        this._startPlayerMaxXp = max;
        this._startPlayerXp = num2;
      }
    }
    this._levelDeltaIsLevelUp = this._targetPlayerLevel > this._startPlayerLevel;
    if (this._levelDeltaIsLevelUp)
      this._levelDeltaValue = this._targetPlayerLevel - this._startPlayerLevel;
    else if (this._targetPlayerLevel == this._startPlayerLevel && this._targetPlayerMaxXp == this._startPlayerMaxXp && this._targetPlayerXp >= this._startPlayerXp)
      this._levelDeltaValue = this._targetPlayerXp - this._startPlayerXp;
    else
      this._levelDeltaValue = 0;
  }

