  private (int level, int xp, int maxXp) ResolveAnimatedLevelProgress(float easedProgress)
  {
    if (this._startPlayerLevel >= this._targetPlayerLevel)
    {
      int targetPlayerMaxXp = this._targetPlayerMaxXp;
      return (this._targetPlayerLevel, PubgStatsScreen.LerpInt(Math.Min(this._startPlayerXp, targetPlayerMaxXp), this._targetPlayerXp, easedProgress), targetPlayerMaxXp);
