    return (double) easedProgress < 0.699999988079071 ? (Math.Clamp(PubgStatsScreen.LerpInt(this._startPlayerLevel, this._targetPlayerLevel, (float) (((double) easedProgress - 0.41999998688697815) / 0.2800000011920929)), this._startPlayerLevel, this._targetPlayerLevel), 0, this._targetPlayerMaxXp) : (this._targetPlayerLevel, PubgStatsScreen.LerpInt(0, this._targetPlayerXp, (float) (((double) easedProgress - 0.41999998688697815 - 0.2800000011920929) / 0.30000004172325134)), this._targetPlayerMaxXp);
  }

  private void UpdateLevelVisualEffects(float linearProgress, float easedProgress, int shownLevel)
  {
    Color from1 = Color.FromHex((ReadOnlySpan<char>) "#4F5E87", new Color?());
    Color to = this._levelDeltaIsLevelUp ? Color.FromHex((ReadOnlySpan<char>) "#FFD96A", new Color?()) : Color.FromHex((ReadOnlySpan<char>) "#8DFFB3", new Color?());
    Color from2 = Color.FromHex((ReadOnlySpan<char>) "#FFD96A", new Color?());
    if (this.LevelPanel.PanelOverride is StyleBoxFlat panelOverride)
    {
      float num1 = (float) (0.5 + 0.5 * (double) MathF.Sin((float) ((double) linearProgress * 3.1415927410125732 * 6.0)));
      float num2 = this._levelDeltaValue > 0 ? (float) ((1.0 - (double) linearProgress) * (0.5 + 0.20000000298023224 * (double) num1)) : (float) ((1.0 - (double) linearProgress) * 0.11999999731779099);
      panelOverride.BorderColor = PubgStatsScreen.LerpColor(from1, to, Math.Clamp(num2, 0.0f, 1f));
    }
    if (this._levelDeltaValue > 0)
    {
      float num3 = (float) (0.40000000596046448 + 0.60000002384185791 * (double) MathF.Sin((float) ((double) linearProgress * 3.1415927410125732 * 4.0)));
      this.LevelValueLabel.FontColorOverride = new Color?(PubgStatsScreen.LerpColor(from2, Color.White, Math.Clamp(num3 * 0.35f, 0.0f, 1f)));
