  private static string FormatSigned(int value)
  {
    if (value < 0)
      return value.ToString();
    return $"+{value}";
  }

  private static string FormatTime(int secondsTotal)
  {
    return $"{secondsTotal / 60:D2}:{secondsTotal % 60:D2}";
  }

  private static int LerpInt(int from, int to, float t)
  {
    return (int) MathF.Round((float) from + (float) (to - from) * t);
  }

  private static float EaseOutCubic(float t)
  {
    float num = 1f - t;
    return (float) (1.0 - (double) num * (double) num * (double) num);
  }

  private static Color LerpColor(Color from, Color to, float t)
  {
    t = Math.Clamp(t, 0.0f, 1f);
    return new Color(from.R + (to.R - from.R) * t, from.G + (to.G - from.G) * t, from.B + (to.B - from.B) * t, from.A + (to.A - from.A) * t);
  }

