    {
      float t = Math.Clamp((float) (((double) time - (double) delay) / 0.23999999463558197), 0.0f, 1f);
      Control control2 = control1;
      Color white = Color.White;
      Color color = ((Color) ref white).WithAlpha(PubgStatsScreen.EaseOutCubic(t));
      control2.Modulate = color;
    }
