        this._battlePassAnimating = false;
        (int level, int xpInLevel, int xpRequired) tuple = PubgStatsScreen.ResolveBattlePassProgress(state, state.CurrentXp);
        this.SetBattlePassProgressDisplay(tuple.level, tuple.xpInLevel, tuple.xpRequired);
        this.SetBattlePassGainLabel(xpGained);
      }
    }
    else
    {
      this._battlePassAnimating = false;
      this.BpSeasonLabel.Text = Loc.GetString("pubg-stats-bp-season-placeholder");
      this.SetBattlePassProgressDisplay(1, 0, 100);
      this.SetBattlePassGainLabel(xpGained);
      this.PopulateBattlePassTasksFallback(fallbackTasks);
      this.BpStateLabel.Text = fallbackTasks == null || fallbackTasks.Count <= 0 ? Loc.GetString("pubg-stats-bp-loading") : Loc.GetString("pubg-stats-bp-state-fallback");
      ((Control) this.BpStateLabel).Visible = true;
    }
  }

  private void PopulateBattlePassTasksFromState(BattlePassStateMessage state)
  {
    List<BattlePassTaskInfo> list = state.Tasks.Where<BattlePassTaskInfo>((Func<BattlePassTaskInfo, bool>) (task => !task.IsSkipped && task.IsCompleted && !task.XpClaimed)).OrderBy<BattlePassTaskInfo, int>((Func<BattlePassTaskInfo, int>) (task => task.Slot)).Take<BattlePassTaskInfo>(5).ToList<BattlePassTaskInfo>();
    List<BattlePassTaskInfo> battlePassTaskInfoList = list.Count > 0 ? list : state.Tasks.Where<BattlePassTaskInfo>((Func<BattlePassTaskInfo, bool>) (task => !task.IsSkipped)).OrderByDescending<BattlePassTaskInfo, float>((Func<BattlePassTaskInfo, float>) (task => task.TargetValue <= 0 ? 0.0f : (float) task.Progress / (float) task.TargetValue)).ThenBy<BattlePassTaskInfo, int>((Func<BattlePassTaskInfo, int>) (task => task.Slot)).Take<BattlePassTaskInfo>(5).ToList<BattlePassTaskInfo>();
    if (battlePassTaskInfoList.Count == 0)
    {
      this.AddBattlePassEmptyRow();
    }
    else
    {
      foreach (BattlePassTaskInfo task in battlePassTaskInfoList)
        ((Control) this.BpTasksContainer).AddChild((Control) this.CreateBattlePassTaskRow(task, task.IsCompleted && !task.XpClaimed));
    }
  }

  private void PopulateBattlePassTasksFallback(List<BattlePassTaskInfo>? tasks)
  {
    if (tasks == null || tasks.Count == 0)
    {
      this.AddBattlePassEmptyRow();
    }
    else
    {
      foreach (BattlePassTaskInfo task in tasks.Take<BattlePassTaskInfo>(5))
        ((Control) this.BpTasksContainer).AddChild((Control) this.CreateBattlePassTaskRow(task, task.IsCompleted && !task.XpClaimed));
    }
  }

