  private void StartBattlePassAnimation(BattlePassStateMessage state, int gainXp)
  {
    this._battlePassAnimationTime = 0.0f;
    this._battlePassAnimating = true;
    this._battlePassTargetGainXp = Math.Max(0, gainXp);
    this._battlePassTargetTotalXp = Math.Max(0, state.CurrentXp);
    this._battlePassStartTotalXp = Math.Max(0, this._battlePassTargetTotalXp - this._battlePassTargetGainXp);
    this.SetBattlePassGainLabel(0);
    (int level, int xpInLevel, int xpRequired) tuple = PubgStatsScreen.ResolveBattlePassProgress(state, this._battlePassStartTotalXp);
    this.SetBattlePassProgressDisplay(tuple.level, tuple.xpInLevel, tuple.xpRequired);
  }

  private void UpdateBattlePassAnimation(float deltaSeconds)
  {
    if (this._battlePassState == null)
    {
      this._battlePassAnimating = false;
    }
    else
    {
      this._battlePassAnimationTime += deltaSeconds;
      double t1 = (double) Math.Clamp(this._battlePassAnimationTime / 1.1f, 0.0f, 1f);
      float t2 = PubgStatsScreen.EaseOutCubic((float) t1);
      int totalXp = PubgStatsScreen.LerpInt(this._battlePassStartTotalXp, this._battlePassTargetTotalXp, t2);
      int gainedXp = PubgStatsScreen.LerpInt(0, this._battlePassTargetGainXp, t2);
      (int level, int xpInLevel, int xpRequired) tuple = PubgStatsScreen.ResolveBattlePassProgress(this._battlePassState, totalXp);
      this.SetBattlePassProgressDisplay(tuple.level, tuple.xpInLevel, tuple.xpRequired);
      this.SetBattlePassGainLabel(gainedXp);
      if (t1 < 1.0)
        return;
      this._battlePassAnimating = false;
      this.SetBattlePassGainLabel(this._battlePassTargetGainXp);
    }
  }

  private void SetBattlePassGainLabel(int gainedXp)
  {
    if (gainedXp <= 0)
    {
      ((Control) this.BpXpLabel).Visible = false;
      this.BpXpLabel.Text = string.Empty;
    }
    else
    {
      ((Control) this.BpXpLabel).Visible = true;
      this.BpXpLabel.Text = Loc.GetString("pubg-stats-bp-xp-earned", new (string, object)[1]
      {
        ("xp", (object) gainedXp)
      });
    }
  }

  private void SetBattlePassProgressDisplay(int level, int xpInLevel, int xpRequired)
  {
    int max = Math.Max(1, xpRequired);
    int num = Math.Clamp(xpInLevel, 0, max);
    this.BpLevelLabel.Text = Loc.GetString("pubg-bp-level", new (string, object)[1]
    {
      (nameof (level), (object) level)
    });
    ((Range) this.BpProgressBar).MinValue = 0.0f;
    ((Range) this.BpProgressBar).MaxValue = (float) max;
    ((Range) this.BpProgressBar).Value = (float) num;
    this.BpProgressTextLabel.Text = Loc.GetString("pubg-bp-xp", new (string, object)[2]
    {
      ("current", (object) num),
      ("required", (object) max)
    });
  }

  private static (int level, int xpInLevel, int xpRequired) ResolveBattlePassProgress(
    BattlePassStateMessage state,
    int totalXp)
  {
    List<BattlePassLevelInfo> list = state.Levels.OrderBy<BattlePassLevelInfo, int>((Func<BattlePassLevelInfo, int>) (level => level.Level)).ToList<BattlePassLevelInfo>();
    if (list.Count == 0)
      return (Math.Max(1, state.CurrentLevel), 0, 100);
    int num1 = Math.Max(0, totalXp);
    foreach (BattlePassLevelInfo battlePassLevelInfo in list)
    {
      int num2 = Math.Max(1, battlePassLevelInfo.XpRequired);
      if (num1 < num2)
        return (battlePassLevelInfo.Level, num1, num2);
      num1 -= num2;
    }
    List<BattlePassLevelInfo> battlePassLevelInfoList = list;
    BattlePassLevelInfo battlePassLevelInfo1 = battlePassLevelInfoList[battlePassLevelInfoList.Count - 1];
    int num3 = Math.Max(1, battlePassLevelInfo1.XpRequired);
    return (Math.Max(battlePassLevelInfo1.Level, state.CurrentLevel), num3, num3);
  }

  private static string BuildTaskTitle(BattlePassTaskInfo task)
  {
    string str;
    switch (task.TaskType)
    {
      case "damage":
        str = Loc.GetString("pubg-bp-task-damage", new (string, object)[1]
        {
          ("value", (object) task.TargetValue)
        });
        break;
      case "kills":
        str = Loc.GetString("pubg-bp-task-kills", new (string, object)[1]
        {
          ("value", (object) task.TargetValue)
        });
        break;
      case "survival":
        str = Loc.GetString("pubg-bp-task-survival", new (string, object)[1]
        {
          ("value", (object) task.TargetValue)
        });
        break;
      default:
        str = Loc.GetString(task.NameKey);
        break;
    }
    return str;
  }

